sql:
SELECT share_user_id, COUNT(share_id) AS total_shares
FROM dataset_shares
GROUP BY share_user_id;

SELECT health_index, life_expectancy
FROM healths
WHERE year = 2015;

SELECT AVG(health_index) AS average_health_index, AVG(life_expectancy) AS average_life_expectancy
FROM healths
WHERE year = 2015;

SELECT download_count 
FROM dataset_downloads 
WHERE dataset_id = 1;

SELECT MAX(social_support_rank) AS highest_rank, social_support
FROM social_supports
WHERE year = 2015;

SELECT request_user_id, COUNT(request_user_id) AS number_of_requests
FROM dataset_requests
GROUP BY request_user_id;

SELECT freedom_index
FROM freedoms
WHERE year = 2015;
